using Nest;
using System;
using System.Collections.Generic;
using System.Linq;

private QueryContainer ApplyFilters(SearchRequest request, QueryContainerDescriptor<SparePartEntity> qcd)
{
    return qcd.Bool(b => b.Filter(fd =>
    {
        var filters = new List<QueryContainer>();
        var dimensionFilter = AddDimensions(request, fd);
        if (dimensionFilter != null)
            filters.Add(dimensionFilter);
        AddKgAndLanguage(request, filters, fd);
        AddPredefinedSolutions(request, filters, fd);

        foreach (var value in Enum.GetValues(typeof(FilterType)).Cast<FilterType>())
        {
            if (value == FilterType.Attribute)
            {
                filters.Add(fd.Terms(t => t.Field(GetTerm(value)).Terms(request.Filters
                    .Where(f => f.FilterType == value)
                    .Select(r => r.Value)
                    .ToArray())));
            }
            else if (value == FilterType.ElevatorManufacturer)
            {
                filters.Add(fd.Terms(t => t.Field(GetTerm(value)).Terms(request.Filters
                    .Where(f => f.FilterType == value)
                    .Select(r => r.Value)
                    .ToArray())));
            }
            else
            {
                filters.Add(fd.Terms(t => t.Field(GetTerm(value)).Terms(request.Filters
                    .Where(f => f.FilterType == value)
                    .Select(r => r.MainAttributeId)
                    .ToArray())));
            }
        }

        return fd.Bool(b => b.Must(filters.ToArray()));
    }));
}

