                if (double.TryParse(cleanStringPart, out value))
                {
                    values.Add(value);
                }
            }
            if (!values.Any())
                return null;
            // fill up with "true" statements
            for (var index = values.Count; index < 3; index++)
            {
                values.Add(double.MinValue);
            }
            var permutations = GetOrderedPermutations(values);
            var fields = new List<Expression<Func<SparePartEntity, object>>>()
      {
        s=>s.Height,
        s=>s.Width,
        s=>s.Length
      };

            var filterPermutations = permutations.
              Select(
                dimensionSet =>
                  dimensionSet.Zip(fields, (v, field) => new { Field = field, Value = v }).
                    Where(result => result.Value != double.MinValue).
                    Select(result =>
                      fd.Range(r => r.OnField(result.Field).GreaterOrEquals(result.Value - tolerance).LowerOrEquals(result.Value + tolerance)) &&
                      fd.Range(r => r.OnField(result.Field).Greater(0))).
                    ToArray()).
              Select(dimensionQueries => fd.And(dimensionQueries)).ToArray();
            return new FilterDescriptor<SparePartEntity>().Or(filterPermutations);
        }

